package day2;

public class Program5_IfElse {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num =0;
		if(num==0) {
			System.out.println("Zero");
		}
		else if(num%2==0) {
			System.out.println("Positive");
		}
		else {
			System.out.println("neagtive");
		}
	}

}
